    }
    
    

    
    /**
     * Ask the OS to tear the tunnel down.
     */override fun `disconnect`()
        = 
    callWithPointer {
    uniffiRustCall() { _status ->
    UniffiLib.INSTANCE.uniffi_ffi_app_fn_method_app_disconnect(
        it, _status)
