     */
    @Throws(AppException::class)override fun `exportProfileUri`(`id`: kotlin.String): kotlin.ByteArray? {
            return FfiConverterOptionalByteArray.lift(
    callWithPointer {
    uniffiRustCallWithError(AppException) { _status ->
    UniffiLib.INSTANCE.uniffi_ffi_app_fn_method_app_export_profile_uri(
        it, FfiConverterString.lower(`id`),_status)
