    }
    )
    }
    

    
    /**
     * Feed an OS connection-status change. `error_code` is a `conn-error` code
     * set only on a failure (see `conn_error::ConnError`).
     */override fun `onOsStatus`(`state`: ConnectionState, `errorCode`: kotlin.Int?)
        = 
    callWithPointer {
    uniffiRustCall() { _status ->
    UniffiLib.INSTANCE.uniffi_ffi_app_fn_method_app_on_os_status(
