            )
            is AppException.Stopped -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: AppException, buf: ByteBuffer) {
        when(value) {
            is AppException.Store -> {
                buf.putInt(1)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
            is AppException.Stopped -> {
                buf.putInt(2)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



/**
 * The OS-derived connection state (mirrors [`model::ConnectionState`]).
 */

enum class ConnectionState {
    
    /**
     * No tunnel is up.
     */
    DISCONNECTED,
    /**
     * The OS reports the tunnel is coming up.
     */
    CONNECTING,
    /**
     * The tunnel is up.
     */
    CONNECTED,
    /**
     * The OS reports the tunnel is tearing down.
     */
    DISCONNECTING;
    companion object
}


/**
 * @suppress
 */
public object FfiConverterTypeConnectionState: FfiConverterRustBuffer<ConnectionState> {
    override fun read(buf: ByteBuffer) = try {
        ConnectionState.values()[buf.getInt() - 1]
    } catch (e: IndexOutOfBoundsException) {
        throw RuntimeException("invalid enum value, something is very wrong!!", e)
    }

    override fun allocationSize(value: ConnectionState) = 4UL

    override fun write(value: ConnectionState, buf: ByteBuffer) {
        buf.putInt(value.ordinal + 1)
    }
}







/**
 * A secret-free failure from a [`SecureStore`] backend.
 */
sealed class SecureStoreException: kotlin.Exception() {
    
    /**
     * The backend (Keychain/Keystore/DPAPI) failed.
     */
    class Backend(
        
        /**
         * A secret-free description.
         */
        val `message`: kotlin.String
        ) : SecureStoreException() {
        override val message
            get() = "message=${ `message` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<SecureStoreException> {
        override fun lift(error_buf: RustBuffer.ByValue): SecureStoreException = FfiConverterTypeSecureStoreError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeSecureStoreError : FfiConverterRustBuffer<SecureStoreException> {
    override fun read(buf: ByteBuffer): SecureStoreException {
        

        return when(buf.getInt()) {
            1 -> SecureStoreException.Backend(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: SecureStoreException): ULong {
        return when(value) {
            is SecureStoreException.Backend -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`message`)
            )
        }
    }

    override fun write(value: SecureStoreException, buf: ByteBuffer) {
        when(value) {
            is SecureStoreException.Backend -> {
                buf.putInt(1)
                FfiConverterString.write(value.`message`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalInt: FfiConverterRustBuffer<kotlin.Int?> {
    override fun read(buf: ByteBuffer): kotlin.Int? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterInt.read(buf)
    }

    override fun allocationSize(value: kotlin.Int?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterInt.allocationSize(value)
        }
    }

    override fun write(value: kotlin.Int?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterInt.write(value, buf)
        }
    }
}




