/**
 * @suppress
 */
public object FfiConverterSequenceTypeProfileEntry: FfiConverterRustBuffer<List<ProfileEntry>> {
    override fun read(buf: ByteBuffer): List<ProfileEntry> {
        val len = buf.getInt()
        return List<ProfileEntry>(len) {
            FfiConverterTypeProfileEntry.read(buf)
        }
    }

    override fun allocationSize(value: List<ProfileEntry>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterTypeProfileEntry.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<ProfileEntry>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterTypeProfileEntry.write(it, buf)
        }
    }
}

